import React, { createContext, useState, useContext, useEffect } from 'react';
import api from '../utils/api';

// Create the auth context
const AuthContext = createContext(null);

// Custom hook to use the auth context
export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('auth_token'));
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Get current user from token
  const getCurrentUser = async () => {
    if (!token) {
      setLoading(false);
      setIsAuthenticated(false);
      return;
    }

    try {
      // Try loading user data from localStorage first for instant UI
      const storedUser = localStorage.getItem('current_user');
      if (storedUser) {
        try {
          const parsed = JSON.parse(storedUser);
          setCurrentUser(parsed);
          setIsAuthenticated(true);
        } catch (parseErr) {
          console.error('Error parsing stored user:', parseErr);
          // Continue to fetch from API if parsing fails
        }
      }

      // Then fetch from API to ensure data is fresh
      const response = await api.get('/user/user/');
      const userData = response.data;

      setCurrentUser(userData);
      setIsAuthenticated(true);
      localStorage.setItem('current_user', JSON.stringify(userData));
    } catch (err) {
      console.error('Failed to get current user:', err);

      if (err.response && err.response.status === 401) {
        // Token is invalid, clear it
        logout();
      } else {
        // Other errors - keep any user data we loaded from localStorage
        setError('Error fetching user data. Please try again later.');
      }
    } finally {
      setLoading(false);
    }
  };

  // Register a new user
  const register = async (username, password, email, wallet_address) => {
    setLoading(true);
    setError(null);

    try {
      await api.post('/user/register/', {
        username,
        password,
        email,
        wallet_address,
      });

      return true;
    } catch (err) {
      console.error('Registration error:', err);
      setError(err.response?.data?.detail || 'Registration failed. Please try again.');
      return false;
    } finally {
      setLoading(false);
    }
  };

  // Login a user
  const login = async (username, password) => {
    setLoading(true);
    setError(null);

    try {
      const response = await api.post('/user/login/', {
        username,
        password,
      });

      const { access_token } = response.data;

      // Store token in localStorage and state
      localStorage.setItem('auth_token', access_token);
      setToken(access_token);
      setIsAuthenticated(true);

      // Get user data
      await getCurrentUser();

      return true;
    } catch (err) {
      console.error('Login error:', err);
      setError(err.response?.data?.detail || 'Login failed. Please check your credentials.');
      return false;
    } finally {
      setLoading(false);
    }
  };

  // Logout the user
  const logout = () => {
    // Remove token and user from localStorage
    localStorage.removeItem('auth_token');
    localStorage.removeItem('current_user');

    // Reset state
    setToken(null);
    setCurrentUser(null);
    setIsAuthenticated(false);
    setError(null);
  };

  // Effect to fetch current user when the component mounts or token changes
  useEffect(() => {
    getCurrentUser();
  }, [token]);

  // Value object to be provided by the context
  const value = {
    currentUser,
    isAuthenticated,
    loading,
    error,
    register,
    login,
    logout,
    setError,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export default AuthContext;
